const r = $input.first().json;
const moon = r.moon || {};
const scorpius = r.scorpius || {};
const seeing = r.seeing || {};
const targets = r.best_targets_tonight || [];
const planets = r.visible_planets || [];
const mustSee = r.must_see || [];

const lines = [
  `🔭 *StarGazer — Tonight's Report*`,
  `📅 ${r.date || 'Tonight'}`,
  ``,
  `*🌤 Conditions*`,
  `• Seeing: ${seeing.seeing_label || 'N/A'}`,
  `• Go/No-Go: ${seeing.go_nogo || '❓'}`,
  `• Cloud cover: ${seeing.tonight_cloud_pct ?? 'N/A'}%`,
  ``,
  `*🌙 Moon*`,
  `• ${moon.phase_name || 'N/A'} (${moon.illumination_pct ?? '?'}% lit)`,
  `• Rise: ${moon.moonrise || 'N/A'} | Set: ${moon.moonset || 'N/A'}`,
  `• ${moon.dso_impact || ''}`,
  ``,
  `*🦂 Scorpius*`,
  `• ${scorpius.status || 'N/A'}`,
  `• Culminates at ${scorpius.culmination_time || 'N/A'} (${scorpius.culmination_altitude_deg || '?'}°)`,
  ``,
  `*🌟 Must-See Tonight*`,
  ...mustSee.slice(0, 5).map(i => `• ${i}`),
];

if (targets.length > 0) {
  lines.push('');
  lines.push('*🎯 Top Targets Now*');
  targets.slice(0, 4).forEach(t => {
    lines.push(`• ${t.emoji || '•'} ${t.name} — ${t.altitude_deg}° ${t.direction}`);
  });
}

if (planets.length > 0) {
  lines.push('');
  lines.push('*🪐 Visible Planets*');
  planets.slice(0, 4).forEach(p => {
    lines.push(`• ${p.emoji} ${p.name}: ${p.altitude_deg}° ${p.direction}`);
  });
}

lines.push('');
lines.push(`*⏰ Dark Window: ${r.astronomical_dusk || '?'} → ${r.astronomical_dawn || '?'}*`);
lines.push(``);
lines.push(`_📡 Celestron 5" DX | Columbus OH_`);

return [{ json: { text: lines.join('\n') } }];
